module RefModule (
	input clk,
	input reset,
	input preset,
	input [7:0] preset_data,
	output reg [7:0] count);

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (reset)
			count <= 8'b00000000;
		else if (preset)
			count <= preset_data;
		else
			count <= count + 1;
	end

endmodule
